"use strict";exports.id=3311,exports.ids=[3311],exports.modules={23311:a=>{a.exports=JSON.parse('{"source":"ANVISA","documentId":"RDC 169/2024","version":"2024-06","description":"巴西化妆品标签法规 - 强制标识要求","rules":[{"ruleId":"BR-LABEL-001","category":"label","target":"Product name in Portuguese","aliases":["Nome em portugu\xeas","葡萄牙语产品名","名称葡语化"],"severity":"critical","condition":"产品名称必须翻译为葡萄牙语","message":"根据RDC 169/2024，在巴西销售的产品名称必须使用葡萄牙语","sourceUrl":"https://www.gov.br/anvisa/pt-br/assuntos/cosmeticos/legislacao-vigente-1"},{"ruleId":"BR-LABEL-002","category":"label","target":"INCI name","aliases":["Nome INCI","INCI命名","国际成分命名"],"severity":"critical","condition":"成分表必须使用INCI国际命名","message":"成分表必须使用INCI（国际化妆品成分命名）标准","sourceUrl":"https://www.gov.br/anvisa/pt-br/assuntos/cosmeticos/legislacao-vigente-1"},{"ruleId":"BR-LABEL-003","category":"label","target":"Manufacturer info","aliases":["Dados do fabricante","制造商信息"],"severity":"critical","condition":"必须标注制造商或进口商信息","message":"必须标注制造商或进口商的名称、地址和CNPJ","sourceUrl":"https://www.gov.br/anvisa/pt-br/assuntos/cosmeticos/legislacao-vigente-1"},{"ruleId":"BR-LABEL-004","category":"label","target":"Country of origin","aliases":["Pa\xeds de origem","原产国"],"severity":"critical","condition":"必须标注原产国","message":"进口产品必须标注原产国","sourceUrl":"https://www.gov.br/anvisa/pt-br/assuntos/cosmeticos/legislacao-vigente-1"},{"ruleId":"BR-LABEL-005","category":"label","target":"Net content","aliases":["Conte\xfado l\xedquido","净含量"],"severity":"critical","condition":"必须标注净含量","message":"必须标注产品净含量，使用公制单位（g, mL）","sourceUrl":"https://www.gov.br/anvisa/pt-br/assuntos/cosmeticos/legislacao-vigente-1"},{"ruleId":"BR-LABEL-006","category":"label","target":"Batch number","aliases":["N\xfamero do lote","批号"],"severity":"warning","condition":"必须标注生产批号","message":"必须标注生产批号以便产品追溯","sourceUrl":"https://www.gov.br/anvisa/pt-br/assuntos/cosmeticos/legislacao-vigente-1"},{"ruleId":"BR-LABEL-007","category":"label","target":"Expiration date","aliases":["Data de validade","有效期"],"severity":"critical","condition":"必须标注有效期","message":"必须标注有效期（日期或开盖后使用期限PAO）","sourceUrl":"https://www.gov.br/anvisa/pt-br/assuntos/cosmeticos/legislacao-vigente-1"},{"ruleId":"BR-LABEL-008","category":"label","target":"Storage conditions","aliases":["Condi\xe7\xf5es de armazenamento","储存条件"],"severity":"info","condition":"建议标注","message":"建议标注储存条件（如\'避光保存\'、\'室温保存\'）","sourceUrl":"https://www.gov.br/anvisa/pt-br/assuntos/cosmeticos/legislacao-vigente-1"},{"ruleId":"BR-LABEL-009","category":"label","target":"Registration number","aliases":["N\xfamero de registro","注册编号"],"severity":"critical","condition":"必须标注ANVISA注册编号","message":"必须标注ANVISA注册编号（除非是豁免注册的产品）","sourceUrl":"https://www.gov.br/anvisa/pt-br/assuntos/cosmeticos/legislacao-vigente-1"},{"ruleId":"BR-LABEL-010","category":"label","target":"Consumer service","aliases":["SAC","Servi\xe7o de Atendimento ao Consumidor","客服电话"],"severity":"critical","condition":"必须标注客服联系方式","message":"必须标注消费者服务电话或邮箱","sourceUrl":"https://www.gov.br/anvisa/pt-br/assuntos/cosmeticos/legislacao-vigente-1"}]}')}};